import{_ as t,o as r,c as s,a2 as i}from"./chunks/framework.Cuq8tsM6.js";const c=JSON.parse('{"title":"Facturation & Paiements","description":"","frontmatter":{"title":"Facturation & Paiements"},"headers":[],"relativePath":"docs/fr/faq/billing.md","filePath":"docs/fr/faq/billing.md"}'),a={name:"docs/fr/faq/billing.md"};function o(n,e,d,l,p,m){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="facturation-paiements" tabindex="-1">Facturation &amp; Paiements <a class="header-anchor" href="#facturation-paiements" aria-label="Permalink to &quot;Facturation &amp; Paiements&quot;">​</a></h1><details style="margin-bottom:10px;border:1px solid #e1e4e8;border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Je ne vois pas mes revenus dans mon Wallet</summary><div style="margin-top:10px;padding-left:20px;border-left:2px solid #eee;"> Le crédit n&#39;est pas automatique à la signature, mais à la <strong>réalisation</strong>. <ul><li><strong>Asile Colis :</strong> Avez-vous rempli votre déclaration de volume hebdomadaire ? (Le lundi/mardi).</li><li><strong>Email :</strong> Avez-vous cliqué sur &quot;Valider la diffusion&quot; après l&#39;envoi ?</li></ul> Sans cette action manuelle de l&#39;éditeur, les fonds restent séquestrés. </div></details><details style="margin-bottom:10px;border:1px solid #e1e4e8;border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Comment retirer mes gains et éditer ma facture ?</summary><div style="margin-top:10px;padding-left:20px;border-left:2px solid #eee;"> Allez dans <strong>Transaction &gt; Exchange</strong> et cliquez sur <code>Retirer</code>. Saisissez le montant. <br><br><strong>Important :</strong> Si des frais de gestion s&#39;appliquent, éditez votre facture en conséquence du montant net reçu. </div></details><details style="margin-bottom:10px;border:1px solid #e1e4e8;border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">À partir de quand est-ce les revenus sont-ils disponibles ?</summary><div style="margin-top:10px;padding-left:20px;border-left:2px solid #eee;"> Le revenu de la campagne est versé au solde de votre compte 30 jours après le dernier reporting de la campagne. Choisissez ensuite si vous souhaitez <code>Transférer vers le wallet</code> ou <code>Retirer</code> vos revenus. </div></details><details style="margin-bottom:10px;border:1px solid #e1e4e8;border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Quand sont émis les paiements ?</summary><div style="margin-top:10px;padding-left:20px;border-left:2px solid #eee;"> Les paiements sont émis à <strong>30 jours fin de mois</strong>, date de réception de la demande de retrait, à condition que la facture soumise soit valide. </div></details><details style="margin-bottom:10px;border:1px solid #e1e4e8;border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Puis-je réinvestir mes gains ?</summary><div style="margin-top:10px;padding-left:20px;border-left:2px solid #eee;"> Oui, sans frais ! Dans la partie <strong>Exchange</strong>, cliquez sur <code>Transférer vers le wallet</code>. Vous pourrez utiliser ce solde immédiatement pour acheter du trafic pour votre propre site. </div></details>',6)])])}const g=t(a,[["render",o]]);export{c as __pageData,g as default};
